INSERT INTO public.play_questions (domain, category, difficulty_rating, content, options, correct_answer_index, explanation)
VALUES
  ('academic', 'chemistry', 1380, $k001c${"text":"Why does the \\(4s\\) orbital fill before \\(3d\\) in K, yet \\(4s\\) electrons are usually removed before \\(3d\\) when ionizing transition metals?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"atomic_bonding"}$k001c$::jsonb, $k001o$["\\(4s\\) penetrates more in neutral atoms (lower energy first), but once \\(3d\\) fills it shields \\(4s\\), raising \\(4s\\) energy so \\(4s\\) ionizes first.","Because \\(4s\\) always has higher energy than \\(3d\\) in every atom.","Because Hund’s rule forces \\(3d\\) to empty before \\(4s\\).","Because \\(4s\\) is non-bonding in all transition metals."]$k001o$::jsonb, 0, $k001e$Neutral-atom filling follows \((n+l)\) ordering; after \(3d\) occupation, effective nuclear charge and shielding reorder orbital energies for ionization.$k001e$),
  ('academic', 'chemistry', 1386, $k002c${"text":"For a \\(5d\\) hydrogen-like orbital, how many radial and angular nodes are there?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"atomic_bonding"}$k002c$::jsonb, $k002o$["Radial = 2, angular = 2","Radial = 3, angular = 2","Radial = 2, angular = 3","Radial = 1, angular = 2"]$k002o$::jsonb, 0, $k002e$Radial nodes \(= n - l - 1 = 5 - 2 - 1 = 2\); angular nodes \(= l = 2\).$k002e$),
  ('academic', 'chemistry', 1392, $k003c${"text":"According to MOT, why is \\(O_2\\) paramagnetic despite an even electron count?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"atomic_bonding"}$k003c$::jsonb, $k003o$["Two unpaired electrons in degenerate \\(\\pi^*\\) orbitals (Hund’s rule).","Because \\(O_2\\) has a permanent electric dipole only.","Because all electrons are paired in bonding orbitals.","Because oxygen is a liquid at low temperature."]$k003o$::jsonb, 0, $k003e$HOMO are \(\pi^*_{2p}\); the last two electrons occupy separate \(\pi^*\) orbitals with parallel spins.$k003e$),
  ('academic', 'chemistry', 1398, $k004c${"text":"Formal charge on the central oxygen in ozone (\\(O_3\\))?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"atomic_bonding"}$k004c$::jsonb, $k004o$["\\(+1\\)","\\(0\\)","\\(-1\\)","\\(+2\\)"]$k004o$::jsonb, 0, $k004e$FC = valence − lone pairs − bonding/2: \(6 - 2 - 6/2 = +1\).$k004e$),
  ('academic', 'chemistry', 1404, $k005c${"text":"In VSEPR, why do lone pair–lone pair repulsions distort bond angles more than bond pair–bond pair repulsions?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"atomic_bonding"}$k005c$::jsonb, $k005o$["Lone pairs are more diffuse (localized on one nucleus), occupying more angular space and repelling more strongly.","Lone pairs are always smaller than bonding pairs.","Bonding pairs have higher nuclear charge than lone pairs.","Lone pairs only repel other lone pairs, not bond pairs."]$k005o$::jsonb, 0, $k005e$Bonding pairs are shared between two nuclei and more compact; lone pairs spread out.$k005e$),
  ('academic', 'chemistry', 1411, $k006c${"text":"Bond order of \\(N_2^+\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"atomic_bonding"}$k006c$::jsonb, $k006o$["\\(2.5\\)","\\(3\\)","\\(2\\)","\\(3.5\\)"]$k006o$::jsonb, 0, $k006e$\(N_2\) BO = 3; remove one electron from a bonding \(\sigma_{2pz}\) orbital → BO decreases by 0.5.$k006e$),
  ('academic', 'chemistry', 1417, $k007c${"text":"Why is the dipole moment of \\(NH_3\\) (\\(\\sim 1.47\\ \\mathrm{D}\\)) much larger than that of \\(NF_3\\) (\\(\\sim 0.24\\ \\mathrm{D}\\))?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"atomic_bonding"}$k007c$::jsonb, $k007o$["In \\(NH_3\\), bond dipoles add with the lone pair dipole; in \\(NF_3\\), very electronegative F pulls bond dipoles opposite to the lone pair, partly cancelling.","Because \\(NF_3\\) has no lone pair on nitrogen.","Because \\(NH_3\\) is always non-polar.","Because dipole moment depends only on molecular mass."]$k007o$::jsonb, 0, $k007e$Vector addition of bond and lone-pair contributions differs in the two pyramids.$k007e$),
  ('academic', 'chemistry', 1423, $k008c${"text":"An electron in hydrogen falls from \\(n = 4\\) to \\(n = 2\\). Wavelength of the emitted photon? (\\(R_H = 109677\\ \\mathrm{cm^{-1}}\\)).","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"atomic_bonding"}$k008c$::jsonb, $k008o$["\\(\\approx 486\\ \\mathrm{nm}\\) (Balmer blue-green line)","\\(\\approx 656\\ \\mathrm{nm}\\)","\\(\\approx 122\\ \\mathrm{nm}\\)","\\(\\approx 1000\\ \\mathrm{nm}\\)"]$k008o$::jsonb, 0, $k008e$\(1/\lambda = R_H(1/4 - 1/16) = 3R_H/16\); invert to get \(\lambda\).$k008e$),
  ('academic', 'chemistry', 1429, $k009c${"text":"Which has greater covalent character, \\(NaCl\\) or \\(CuCl\\), and why?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"atomic_bonding"}$k009c$::jsonb, $k009o$["\\(CuCl\\) — \\(Cu^+\\) is more polarizing (pseudo-noble \\(3d^{10}\\) etc.), Fajans-type distortion of \\(Cl^-\\).","\\(NaCl\\) — sodium is lighter.","They are identical in every crystal.","\\(NaCl\\) — higher lattice energy always means more covalent character."]$k009o$::jsonb, 0, $k009e$Smaller, more polarizing cation pulls electron density from anion into the bond region.$k009e$),
  ('academic', 'chemistry', 1435, $k010c${"text":"Heisenberg: if \\(\\Delta x = \\Delta p\\) for a particle of mass \\(m\\), express \\(\\Delta v\\).","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"atomic_bonding"}$k010c$::jsonb, $k010o$["\\(\\Delta v = \\dfrac{1}{2m}\\sqrt{\\dfrac{h}{\\pi}}\\)","\\(\\Delta v = \\dfrac{h}{4\\pi m\\Delta x}\\) only, with \\(\\Delta x\\) arbitrary","\\(\\Delta v = \\sqrt{h/(2\\pi m)}\\)","\\(\\Delta v = 0\\)"]$k010o$::jsonb, 0, $k010e$\(\Delta x\,\Delta p \ge h/(4\pi)\); set \(\Delta x = \Delta p\) and use \(\Delta p = m\Delta v\).$k010e$),
  ('academic', 'chemistry', 1442, $k011c${"text":"Compared to Trouton’s rule \\(\\Delta S_{\\mathrm{vap}} \\approx 85\\ \\mathrm{J\\,K^{-1}\\,mol^{-1}}\\) for many liquids, how does water’s \\(\\Delta S_{\\mathrm{vap}}\\) behave?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"thermo_kinetics"}$k011c$::jsonb, $k011o$["Water’s \\(\\Delta S_{\\mathrm{vap}}\\) is typically higher because the liquid is strongly ordered (H-bonds), so vaporization gives an unusually large disorder jump.","Water’s \\(\\Delta S_{\\mathrm{vap}}\\) is always lower because hydrogen bonds make vaporization impossible.","Water follows Trouton exactly because it is molecular.","Trouton’s rule does not apply to any liquids."]$k011o$::jsonb, 0, $k011e$Highly ordered liquid → larger entropy gain on forming a disordered gas.$k011e$),
  ('academic', 'chemistry', 1448, $k012c${"text":"A first-order reaction is 75% complete in 60 min. Half-life \\(t_{1/2}\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"thermo_kinetics"}$k012c$::jsonb, $k012o$["\\(30\\ \\mathrm{min}\\)","\\(15\\ \\mathrm{min}\\)","\\(60\\ \\mathrm{min}\\)","\\(45\\ \\mathrm{min}\\)"]$k012o$::jsonb, 0, $k012e$75% complete ⇒ 25% left ⇒ two half-lives in 60 min ⇒ \(t_{1/2} = 30\ \mathrm{min}\).$k012e$),
  ('academic', 'chemistry', 1454, $k013c${"text":"When is \\(\\Delta G < 0\\) guaranteed at **all** temperatures for a reaction?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"thermo_kinetics"}$k013c$::jsonb, $k013o$["\\(\\Delta H < 0\\) and \\(\\Delta S > 0\\)","\\(\\Delta H > 0\\) and \\(\\Delta S < 0\\)","\\(\\Delta H > 0\\) and \\(\\Delta S > 0\\) always","\\(\\Delta S = 0\\) only"]$k013o$::jsonb, 0, $k013e$\(\Delta G = \Delta H - T\Delta S\); both terms favor spontaneity for every \(T\).$k013e$),
  ('academic', 'chemistry', 1460, $k014c${"text":"2 mol ideal gas expands isothermally and reversibly at \\(300\\ \\mathrm{K}\\) from 10 L to 100 L. Work done on the gas? (\\(R \\approx 8.314\\ \\mathrm{J\\,K^{-1}\\,mol^{-1}}\\)).","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"thermo_kinetics"}$k014c$::jsonb, $k014o$["\\(\\approx -11.5\\ \\mathrm{kJ}\\)","\\(+11.5\\ \\mathrm{kJ}\\)","\\(-2.30\\ \\mathrm{kJ}\\)","\\(0\\ \\mathrm{kJ}\\)"]$k014o$::jsonb, 0, $k014e$\(W = -2.303\,nRT\log(V_2/V_1)\).$k014e$),
  ('academic', 'chemistry', 1466, $k015c${"text":"Collision theory: why do many exothermic reactions still need activation energy?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"thermo_kinetics"}$k015c$::jsonb, $k015o$["Bonds in reactants must be stretched/broken to reach the transition state; repulsion and geometry require a minimum collision energy.","Exothermic reactions have no transition state.","Activation energy only exists for endothermic reactions.","Heat always flows in without a barrier."]$k015o$::jsonb, 0, $k015e$\(E_a\) is the barrier to forming the activated complex, independent of overall \(\Delta H\).$k015e$),
  ('academic', 'chemistry', 1473, $k016c${"text":"Temperature coefficient of rate is 2 per \\(10\\ \\mathrm{K}\\). Factor increase from \\(20^\\circ\\mathrm{C}\\) to \\(50^\\circ\\mathrm{C}\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"thermo_kinetics"}$k016c$::jsonb, $k016o$["\\(8\\)","\\(4\\)","\\(16\\)","\\(2\\)"]$k016o$::jsonb, 0, $k016e$\(2^{\Delta T/10} = 2^3 = 8\).$k016e$),
  ('academic', 'chemistry', 1479, $k017c${"text":"In thermodynamics, is work a state function or a path function?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"thermo_kinetics"}$k017c$::jsonb, $k017o$["Path function — depends on how the system goes from initial to final state.","State function — depends only on endpoints.","Always zero for cycles.","Equal to heat in all processes."]$k017o$::jsonb, 0, $k017e$Different paths (reversible vs irreversible expansion) give different \(W\).$k017e$),
  ('academic', 'chemistry', 1485, $k018c${"text":"For \\(N_2 + 3H_2 \\rightarrow 2NH_3\\), if \\(-d[H_2]/dt = 3 \\times 10^{-4}\\ \\mathrm{M\\,s^{-1}}\\), what is \\(+\\,d[NH_3]/dt\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"thermo_kinetics"}$k018c$::jsonb, $k018o$["\\(2 \\times 10^{-4}\\ \\mathrm{M\\,s^{-1}}\\)","\\(3 \\times 10^{-4}\\ \\mathrm{M\\,s^{-1}}\\)","\\(1 \\times 10^{-4}\\ \\mathrm{M\\,s^{-1}}\\)","\\(9 \\times 10^{-4}\\ \\mathrm{M\\,s^{-1}}\\)"]$k018o$::jsonb, 0, $k018e$Stoichiometry: \(\frac{1}{3}d[H_2]/dt\) linked to \(\frac{1}{2}d[NH_3]/dt\).$k018e$),
  ('academic', 'chemistry', 1491, $k019c${"text":"Why does a catalyst not change \\(K_{\\mathrm{eq}}\\) for a reversible reaction?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"thermo_kinetics"}$k019c$::jsonb, $k019o$["It lowers \\(E_a\\) for forward and reverse by the same factor, speeding both equally; equilibrium composition unchanged.","It shifts equilibrium toward products only.","It changes \\(\\Delta H^\\circ\\) of the reaction.","It consumes one of the reactants permanently."]$k019o$::jsonb, 0, $k019e$Equal acceleration of forward and reverse rates leaves \(K\) the same.$k019e$),
  ('academic', 'chemistry', 1497, $k020c${"text":"\\(\\Delta H_f^\\circ\\): \\(CO_2\\) \\(-393.5\\), \\(H_2O(l)\\) \\(-285.8\\), \\(CH_4\\) \\(-74.8\\ \\mathrm{kJ\\,mol^{-1}}\\). Standard enthalpy of combustion of methane?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"thermo_kinetics"}$k020c$::jsonb, $k020o$["\\(-890.3\\ \\mathrm{kJ\\,mol^{-1}}\\)","\\(-802.1\\ \\mathrm{kJ\\,mol^{-1}}\\) only","\\(+890.3\\ \\mathrm{kJ\\,mol^{-1}}\\)","\\(-600.0\\ \\mathrm{kJ\\,mol^{-1}}\\)"]$k020o$::jsonb, 0, $k020e$\(CH_4 + 2O_2 \rightarrow CO_2 + 2H_2O\); use products minus reactants.$k020e$),
  ('academic', 'chemistry', 1504, $k021c${"text":"Le Chatelier: adding an inert gas to a gaseous equilibrium at **constant volume** — effect?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"equilibrium"}$k021c$::jsonb, $k021o$["No shift — partial pressures of reactants/products unchanged.","Shifts toward fewer moles of gas.","Shifts toward more moles of gas.","Always increases \\(K_p\\)."]$k021o$::jsonb, 0, $k021e$Total pressure rises but mole fractions and partial pressures of reacting gases stay the same.$k021e$),
  ('academic', 'chemistry', 1510, $k022c${"text":"pH of \\(10^{-8}\\ \\mathrm{M}\\) HCl in water at \\(25^\\circ\\mathrm{C}\\) (include water autoionization).","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"equilibrium"}$k022c$::jsonb, $k022o$["\\(\\approx 6.96\\)–\\(7.0\\) (often quoted \\(\\approx 6.98\\))","Exactly \\(8.0\\)","Exactly \\(7.0\\) always","\\(8.0\\)"]$k022o$::jsonb, 0, $k022e$\([H^+] \approx 10^{-8} + 10^{-7}\); \(\mathrm{pH} = -\log[H^+]\).$k022e$),
  ('academic', 'chemistry', 1516, $k023c${"text":"Why does a common ion decrease the solubility of a sparingly soluble salt?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"equilibrium"}$k023c$::jsonb, $k023o$["\\(Q_{\\mathrm{sp}}\\) exceeds \\(K_{\\mathrm{sp}}\\); equilibrium shifts to precipitate solid until \\(Q = K\\) again.","It increases \\(K_{\\mathrm{sp}}\\) directly.","It removes water from the solution.","Common ions always increase solubility."]$k023o$::jsonb, 0, $k023e$Added ion raises ion product; Le Chatelier reduces dissolved amount.$k023e$),
  ('academic', 'chemistry', 1522, $k024c${"text":"\\(A(g) + B(g) \\rightleftharpoons C(g)\\), \\(K_c = 10\\) at \\(300\\ \\mathrm{K}\\). \\(K_p\\)? (\\(R = 0.0821\\ \\mathrm{L\\,atm\\,K^{-1}\\,mol^{-1}}\\)).","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"equilibrium"}$k024c$::jsonb, $k024o$["\\(\\approx 0.406\\)","\\(10\\)","\\(246\\)","\\(0.041\\)"]$k024o$::jsonb, 0, $k024e$\(K_p = K_c(RT)^{\Delta n}\), \(\Delta n = -1\).$k024e$),
  ('academic', 'chemistry', 1528, $k025c${"text":"In an acidic buffer \\(HA / A^-\\), what happens to \\([A^-]/[HA]\\) when a little strong acid is added?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"equilibrium"}$k025c$::jsonb, $k025o$["The ratio **decreases** — \\(H^+\\) protonates \\(A^-\\) to \\(HA\\).","The ratio increases.","The ratio stays exactly 1 always.","\\(pH\\) does not change at all."]$k025o$::jsonb, 0, $k025e$Added \(H^+\) consumes conjugate base.$k025e$),
  ('academic', 'chemistry', 1535, $k026c${"text":"\\(K_{\\mathrm{sp}}\\) of \\(Ag_2CrO_4\\) is \\(3.2 \\times 10^{-11}\\). Molar solubility \\(s\\) in pure water?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"equilibrium"}$k026c$::jsonb, $k026o$["\\(2 \\times 10^{-4}\\ \\mathrm{M}\\)","\\(8 \\times 10^{-4}\\ \\mathrm{M}\\)","\\(10^{-4}\\ \\mathrm{M}\\)","\\(4 \\times 10^{-3}\\ \\mathrm{M}\\)"]$k026o$::jsonb, 0, $k026e$\(K_{\mathrm{sp}} = 4s^3\) for \(Ag_2CrO_4 \rightleftharpoons 2Ag^+ + CrO_4^{2-}\).$k026e$),
  ('academic', 'chemistry', 1541, $k027c${"text":"Stronger Lewis acid: \\(BF_3\\) or \\(BCl_3\\)? Why?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"equilibrium"}$k027c$::jsonb, $k027o$["\\(BCl_3\\) — poorer \\(p\\pi\\)-\\(p\\pi\\) back-donation from Cl (larger \\(3p\\)) leaves B more electron-deficient.","\\(BF_3\\) — fluorine is always a stronger donor.","They are identical in Lewis acidity.","\\(BF_3\\) because F is smaller only."]$k027o$::jsonb, 0, $k027e$Back-bonding stabilizes \(BF_3\) more than \(BCl_3\).$k027e$),
  ('academic', 'chemistry', 1547, $k028c${"text":"Degree of dissociation \\(\\alpha\\) of \\(0.1\\ \\mathrm{M}\\) acetic acid (\\(K_a = 1.8 \\times 10^{-5}\\)).","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"equilibrium"}$k028c$::jsonb, $k028o$["\\(\\approx 0.013\\) (\\(\\sim 1.3\\%\\))","\\(0.18\\)","\\(0.0018\\)","\\(1.0\\)"]$k028o$::jsonb, 0, $k028e$\(\alpha \approx \sqrt{K_a/C}\) for weak electrolytes.$k028e$),
  ('academic', 'chemistry', 1553, $k029c${"text":"Why is aqueous \\(Na_2CO_3\\) basic?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"equilibrium"}$k029c$::jsonb, $k029o$["\\(CO_3^{2-}\\) hydrolyzes (salt of strong base + weak acid), producing \\(OH^-\\).","\\(Na^+\\) hydrolyzes strongly.","Carbonate does not react with water.","It is a strong acid salt."]$k029o$::jsonb, 0, $k029e$Anion of weak acid accepts protons from water, releasing hydroxide.$k029e$),
  ('academic', 'chemistry', 1559, $k030c${"text":"Buffer: \\(0.1\\ \\mathrm{M}\\) \\(NH_4OH\\) and \\(0.1\\ \\mathrm{M}\\) \\(NH_4Cl\\), \\(pK_b\\) of ammonia \\(= 4.74\\). pH?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"equilibrium"}$k030c$::jsonb, $k030o$["\\(9.26\\)","\\(4.74\\)","\\(7.00\\)","\\(10.74\\)"]$k030o$::jsonb, 0, $k030e$\(pOH = pK_b + \log([\mathrm{salt}]/[\mathrm{base}])\); \(pH = 14 - pOH\).$k030e$),
  ('academic', 'chemistry', 1566, $k031c${"text":"Why does a galvanic cell’s voltage fall to zero after long operation?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"electrochem_solid"}$k031c$::jsonb, $k031o$["The cell approaches equilibrium (\\(Q \\to K\\)); \\(\\Delta G\\) and \\(E\\) go to zero.","Electrons are used up permanently.","Salt bridge runs out of electrons.","Temperature always drops to absolute zero."]$k031o$::jsonb, 0, $k031e$Nernst: reactant depletion drives \(E\) toward 0.$k031e$),
  ('academic', 'chemistry', 1572, $k032c${"text":"Deposit \\(1.27\\ \\mathrm{g}\\) Cu from \\(Cu^{2+}\\) at \\(2\\ \\mathrm{A}\\). Time? (\\(M_{\\mathrm{Cu}} = 63.5\\ \\mathrm{g\\,mol^{-1}}\\), \\(F = 96500\\ \\mathrm{C\\,mol^{-1}}\\)).","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"electrochem_solid"}$k032c$::jsonb, $k032o$["\\(1930\\ \\mathrm{s}\\)","\\(965\\ \\mathrm{s}\\)","\\(3860\\ \\mathrm{s}\\)","\\(100\\ \\mathrm{s}\\)"]$k032o$::jsonb, 0, $k032e$\(n = 2\) mol e\(^-\) per mol Cu; \(Q = n_e F\); \(t = Q/I\).$k032e$),
  ('academic', 'chemistry', 1578, $k033c${"text":"What is a Frenkel defect in an ionic crystal?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"electrochem_solid"}$k033c$::jsonb, $k033o$["A cation (usually smaller) leaves its lattice site and occupies an interstitial site, leaving a vacancy.","A pair of cation and anion vacancies only.","Loss of entire crystal to solution.","Schottky defect in metals only."]$k033o$::jsonb, 0, $k033e$Vacancy + interstitial of same ion type; density often unchanged.$k033e$),
  ('academic', 'chemistry', 1584, $k034c${"text":"Metal FCC, unit cell edge \\(a\\). Atomic radius \\(r\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"electrochem_solid"}$k034c$::jsonb, $k034o$["\\(r = a/(2\\sqrt{2})\\)","\\(r = a/2\\)","\\(r = a\\sqrt{2}/4\\) written differently only as \\(a/4\\)","\\(r = a/4\\)"]$k034o$::jsonb, 0, $k034e$Face diagonal \(= 4r = \sqrt{2}\,a\).$k034e$),
  ('academic', 'chemistry', 1590, $k035c${"text":"Main role of a salt bridge in a galvanic cell?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"electrochem_solid"}$k035c$::jsonb, $k035o$["Maintains electrical neutrality by ion migration between half-cells.","Generates extra voltage chemically.","Replaces the external wire.","Prevents any redox reaction."]$k035o$::jsonb, 0, $k035e$Counters charge buildup from oxidation/reduction.$k035e$),
  ('academic', 'chemistry', 1597, $k036c${"text":"\\(E^\\circ_{Zn^{2+}/Zn} = -0.76\\ \\mathrm{V}\\), \\(E^\\circ_{Cu^{2+}/Cu} = +0.34\\ \\mathrm{V}\\). \\(\\Delta G^\\circ\\) for Daniell cell per reaction as written (2 e\\(^-\\))?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"electrochem_solid"}$k036c$::jsonb, $k036o$["\\(\\approx -212\\ \\mathrm{kJ\\,mol^{-1}}\\)","\\(+212\\ \\mathrm{kJ\\,mol^{-1}}\\)","\\(-106\\ \\mathrm{kJ\\,mol^{-1}}\\) only","\\(0\\ \\mathrm{kJ\\,mol^{-1}}\\)"]$k036o$::jsonb, 0, $k036e$\(E^\circ_{\mathrm{cell}} = 1.10\ \mathrm{V}\); \(\Delta G^\circ = -nFE^\circ\).$k036e$),
  ('academic', 'chemistry', 1603, $k037c${"text":"Why does doping Si with group 15 (e.g. P) give **n**-type semiconductor?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"electrochem_solid"}$k037c$::jsonb, $k037o$["Extra valence electron is weakly bound and donates conduction electrons.","Holes are the majority carriers.","Phosphorus removes all electrons.","The lattice becomes insulating."]$k037o$::jsonb, 0, $k037e$Pentavalent substituent provides donor levels near the conduction band.$k037e$),
  ('academic', 'chemistry', 1609, $k038c${"text":"Packing efficiency of simple cubic lattice?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"electrochem_solid"}$k038c$::jsonb, $k038o$["\\(\\approx 52.4\\%\\)","\\(74\\%\\)","\\(68\\%\\)","\\(100\\%\\)"]$k038o$::jsonb, 0, $k038e$One atom per cell; \(\pi/6\) sphere fraction of cube for \(a = 2r\).$k038e$),
  ('academic', 'chemistry', 1615, $k039c${"text":"Why does molar conductivity \\(\\Lambda_m\\) of a **weak** electrolyte rise sharply on dilution toward infinite dilution?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"electrochem_solid"}$k039c$::jsonb, $k039o$["Degree of ionization increases strongly as concentration drops.","It is already fully dissociated like strong electrolytes.","Ion mobility decreases to infinity.","Only viscosity changes."]$k039o$::jsonb, 0, $k039e$More ions per mole of solute appear in solution as \(\alpha \to 1\).$k039e$),
  ('academic', 'chemistry', 1621, $k040c${"text":"\\(E^\\circ(Fe^{3+}/Fe^{2+}) = 0.77\\ \\mathrm{V}\\), \\(E^\\circ(I_2/I^-) = 0.54\\ \\mathrm{V}\\). For \\(2Fe^{3+} + 2I^- \\rightarrow 2Fe^{2+} + I_2\\), \\(E^\\circ_{\\mathrm{cell}}\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"electrochem_solid"}$k040c$::jsonb, $k040o$["\\(+0.23\\ \\mathrm{V}\\) (spontaneous under standard conditions)","\\(-0.23\\ \\mathrm{V}\\)","\\(0\\ \\mathrm{V}\\)","\\(+1.31\\ \\mathrm{V}\\)"]$k040o$::jsonb, 0, $k040e$\(E^\circ_{\mathrm{cathode}} - E^\circ_{\mathrm{anode}}\).$k040e$),
  ('academic', 'chemistry', 1628, $k041c${"text":"Why is \\(CF_3COOH\\) a much stronger acid than \\(CH_3COOH\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"goc_stereo"}$k041c$::jsonb, $k041o$["Strong \\(-I\\) effect of F stabilizes the carboxylate anion.","Fluorine donates electrons to the carbonyl only.","Acid strength does not depend on substituents.","\\(CF_3\\) is larger so acid is weaker."]$k041o$::jsonb, 0, $k041e$Electron-withdrawing groups stabilize the conjugate base.$k041e$),
  ('academic', 'chemistry', 1634, $k042c${"text":"How many distinct stereoisomers for 2,3-dichlorobutane?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"goc_stereo"}$k042c$::jsonb, $k042o$["\\(3\\) (one meso + one enantiomeric pair)","\\(4\\)","\\(2\\)","\\(8\\)"]$k042o$::jsonb, 0, $k042e$Two stereocenters with internal plane of symmetry → meso compound counts once.$k042e$),
  ('academic', 'chemistry', 1640, $k043c${"text":"Compare gas-phase stability: **tert-butyl** carbocation vs **benzyl** carbocation (typical textbook competition).","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"goc_stereo"}$k043c$::jsonb, $k043o$["Benzyl is generally more stable — resonance delocalization over the ring dominates in many comparisons.","Methyl carbocation is always most stable.","Primary carbocations are most stable.","Neither is ever observed."]$k043o$::jsonb, 0, $k043e$Benzyl cation is resonance-stabilized; tert-butyl relies on hyperconjugation (exam emphasis varies).$k043e$),
  ('academic', 'chemistry', 1646, $k044c${"text":"Hybridization of C atoms left to right: \\(CH_2=C=CH-CH_3\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"goc_stereo"}$k044c$::jsonb, $k044o$["\\(sp^2,\\ sp,\\ sp^2,\\ sp^3\\)","\\(sp,\\ sp,\\ sp^2,\\ sp^3\\)","\\(sp^3\\) throughout","\\(sp^2\\) throughout"]$k044o$::jsonb, 0, $k044e$Cumulative double bond at middle carbon is \(sp\)-hybridized.$k044e$),
  ('academic', 'chemistry', 1652, $k045c${"text":"Fundamental requirement for optical activity?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"goc_stereo"}$k045c$::jsonb, $k045o$["Chirality — molecule non-superimposable on its mirror image (no improper symmetry in practice).","Presence of oxygen only.","Must be a polymer.","Must absorb UV light."]$k045o$::jsonb, 0, $k045e$Needs asymmetric environment for polarized light interaction.$k045e$),
  ('academic', 'chemistry', 1659, $k046c${"text":"Pure enantiomer \\([\\alpha] = +20^\\circ\\). Mixture shows \\([\\alpha] = +5^\\circ\\). Enantiomeric excess (ee) and %(+) enantiomer?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"goc_stereo"}$k046c$::jsonb, $k046o$["ee \\(\\approx 25\\%\\), \\((+) \\approx 62.5\\%\\)","ee \\(= 75\\%\\), \\((+) = 87.5\\%\\)","ee \\(= 0\\%\\)","ee \\(= 100\\%\\)"]$k046o$::jsonb, 0, $k046e$ee = observed/specific of pure enantiomer; remainder racemic splits equally.$k046e$),
  ('academic', 'chemistry', 1665, $k047c${"text":"Why does \\(S_N2\\) proceed with inversion at the electrophilic carbon?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"goc_stereo"}$k047c$::jsonb, $k047o$["Backside nucleophilic attack \\(180^\\circ\\) to the leaving group inverts the tetrahedron.","Front-side attack is mandatory.","Carbocation planarity causes racemization only.","Solvent always forces retention."]$k047o$::jsonb, 0, $k047e$Walden inversion from concerted mechanism.$k047e$),
  ('academic', 'chemistry', 1671, $k048c${"text":"Naphthalene (\\(C_{10}H_8\\)): count of \\(\\sigma\\) and \\(\\pi\\) bonds?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"goc_stereo"}$k048c$::jsonb, $k048o$["\\(19\\ \\sigma\\), \\(5\\ \\pi\\)","\\(10\\ \\sigma\\), \\(10\\ \\pi\\)","\\(18\\ \\sigma\\), \\(6\\ \\pi\\)","\\(20\\ \\sigma\\), \\(4\\ \\pi\\)"]$k048o$::jsonb, 0, $k048e$Fused aromatic framework: 8 C–H \(\sigma\), 11 C–C \(\sigma\), 5 aromatic \(\pi\) bonds.$k048e$),
  ('academic', 'chemistry', 1677, $k049c${"text":"Stronger base: pyrrole or pyridine?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"goc_stereo"}$k049c$::jsonb, $k049o$["Pyridine — lone pair in \\(sp^2\\) hybrid orbital is localized and available for protonation.","Pyrrole — lone pair is on nitrogen in all cases free.","They are equally basic in water.","Neither accepts protons."]$k049o$::jsonb, 0, $k049e$In pyrrole, lone pair participates in \(6\pi\) aromaticity and is less basic.$k049e$),
  ('academic', 'chemistry', 1683, $k050c${"text":"Absolute configuration at the chiral center of **D-glyceraldehyde** (Fischer projection, standard assignment)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"goc_stereo"}$k050c$::jsonb, $k050o$["\\(R\\)","\\(S\\)","\\(E\\)","\\(Z\\)"]$k050o$::jsonb, 0, $k050e$Priorities OH > CHO > CH2OH > H; D-configuration with H on horizontal gives \(R\) after CIP rules.$k050e$),
  ('academic', 'chemistry', 1690, $k051c${"text":"Why does hydroboration–oxidation of alkenes give an **anti-Markovnikov** alcohol?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"hydrocarbons"}$k051c$::jsonb, $k051o$["BH\\(_2\\) adds to the less hindered carbon; sterics and partial charges in a cyclic transition state place B on the less substituted C; oxidation replaces B with OH.","B always adds to the more substituted carbon.","Markovnikov rule applies unchanged.","Only terminal alkynes react."]$k051o$::jsonb, 0, $k051e$Syn addition followed by retention of stereochemistry at C–B then C–OH.$k051e$),
  ('academic', 'chemistry', 1696, $k052c${"text":"An unknown alkene ozonolysis gives 1 mol acetone and 1 mol acetaldehyde only. IUPAC name?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"hydrocarbons"}$k052c$::jsonb, $k052o$["**2-methylbut-2-ene** (\\(2\\)-methylbut-2-ene)","But-1-ene","2-methylbut-1-ene only","Pent-2-ene"]$k052o$::jsonb, 0, $k052e$Combine carbonyl fragments to rebuild the double bond.$k052e$),
  ('academic', 'chemistry', 1702, $k053c${"text":"EAS: halogens are ortho/para directors yet deactivating — why?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"hydrocarbons"}$k053c$::jsonb, $k053o$["+\\(M\\) resonance donation stabilizes \\(\\sigma\\)-complex at ortho/para; \\(-I\\) withdraws overall electron density (deactivating).","Halogens meta-direct only.","Resonance never occurs for halogens.","They are strong activators."]$k053o$::jsonb, 0, $k053e$Competition between inductive withdrawal and lone-pair donation.$k053e$),
  ('academic', 'chemistry', 1708, $k054c${"text":"1-bromobutane + bulky \\(t\\)-BuOK — major elimination product?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"hydrocarbons"}$k054c$::jsonb, $k054o$["**1-butene** (Hofmann / less substituted alkene)","2-butene only","Butane","Isobutene from rearrangement always"]$k054o$::jsonb, 0, $k054e$Bulky base abstracts the least hindered \(\beta\)-H in \(E2\).$k054e$),
  ('academic', 'chemistry', 1714, $k055c${"text":"Why are terminal alkynes weakly acidic toward strong bases (e.g. \\(NaNH_2\\)) but alkenes are not?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"hydrocarbons"}$k055c$::jsonb, $k055o$["The \\(sp\\)-hybridized C–H bond stabilizes the conjugate acetylide (high s-character).","\\(sp^3\\) C–H is more acidic always.","Alkynes have no acidic hydrogens.","Only aromatic C–H is acidic."]$k055o$::jsonb, 0, $k055e$Greater electronegativity of \(sp\) carbon stabilizes carbanion.$k055e$),
  ('academic', 'chemistry', 1721, $k056c${"text":"Moles of \\(H_2\\) needed to fully hydrogenate 1 mol benzene to cyclohexane?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"hydrocarbons"}$k056c$::jsonb, $k056o$["\\(3\\ \\mathrm{mol}\\)","\\(1\\ \\mathrm{mol}\\)","\\(6\\ \\mathrm{mol}\\)","\\(2\\ \\mathrm{mol}\\)"]$k056o$::jsonb, 0, $k056e$Three \(\pi\) bonds in the aromatic ring.$k056e$),
  ('academic', 'chemistry', 1727, $k057c${"text":"Wurtz reaction with two **different** alkyl halides is impractical for odd-carbon alkanes because…","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"hydrocarbons"}$k057c$::jsonb, $k057o$["You get a mixture of \\(R-R\\), \\(R'-R'\\), and \\(R-R'\\) that is hard to separate.","Odd alkanes cannot form.","Sodium does not react.","Only aromatic products form."]$k057o$::jsonb, 0, $k057e$Statistical coupling gives three products with similar properties.$k057e$),
  ('academic', 'chemistry', 1733, $k058c${"text":"1-butene + HBr in presence of **peroxide** — major product?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"hydrocarbons"}$k058c$::jsonb, $k058o$["**1-bromobutane** (anti-Markovnikov / radical pathway)","2-bromobutane only","Butanol","Butane"]$k058o$::jsonb, 0, $k058e$Peroxide initiates free-radical addition; Br\(^\cdot\) adds to less substituted carbon first.$k058e$),
  ('academic', 'chemistry', 1739, $k059c${"text":"Why does \\(S_N1\\) at a chiral center often give racemization (or partial racemization)?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"hydrocarbons"}$k059c$::jsonb, $k059o$["Planar \\(sp^2\\) carbocation allows attack from either face with similar probability.","Inversion is mandatory.","No intermediate forms.","Solvent excludes the nucleophile."]$k059o$::jsonb, 0, $k059e$Loss of stereochemical information at the flat cation.$k059e$),
  ('academic', 'chemistry', 1745, $k060c${"text":"Industrial Dow process: chlorobenzene to phenol with aqueous NaOH — typical conditions cited?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"hydrocarbons"}$k060c$::jsonb, $k060o$["\\(\\approx 623\\ \\mathrm{K}\\), \\(\\approx 300\\ \\mathrm{atm}\\) (high \\(T,P\\))","\\(298\\ \\mathrm{K}\\), \\(1\\ \\mathrm{atm}\\)","\\(373\\ \\mathrm{K}\\) only","Room temperature, catalyst only"]$k060o$::jsonb, 0, $k060e$Strong C–Cl bond + aromatic stabilization require forcing conditions for nucleophilic substitution.$k060e$),
  ('academic', 'chemistry', 1752, $k061c${"text":"Why are phenols more acidic than simple aliphatic alcohols?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"orgo_on"}$k061c$::jsonb, $k061o$["Phenoxide is resonance-stabilized by delocalization into the aromatic ring.","Phenols have stronger O–H bonds only numerically.","Aliphatic alkoxides are more resonance-stabilized.","pH is unrelated to structure."]$k061o$::jsonb, 0, $k061e$Charge delocalization lowers energy of the conjugate base.$k061e$),
  ('academic', 'chemistry', 1758, $k062c${"text":"Acetaldehyde + dilute NaOH, then heat — final major product?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"orgo_on"}$k062c$::jsonb, $k062o$["**Crotonaldehyde** (but-2-enal, \\(\\alpha,\\beta\\)-unsaturated aldehyde)","Ethanol only","Acetic acid only","3-hydroxybutanal only with no dehydration"]$k062o$::jsonb, 0, $k062e$Aldol then dehydration on heating.$k062e$),
  ('academic', 'chemistry', 1764, $k063c${"text":"Gabriel synthesis: why is it unsuitable for preparing **primary aromatic** amines from aryl halides?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"orgo_on"}$k063c$::jsonb, $k063o$["Aryl halides do not undergo facile \\(S_N2\\) backside attack on the ring carbon.","Aromatic amines are too basic for Gabriel.","Phthalimide only reacts with tertiary halides.","It only makes quaternary salts."]$k063o$::jsonb, 0, $k063e$Need aliphatic \(S_N2\)-active substrate.$k063e$),
  ('academic', 'chemistry', 1770, $k064c${"text":"Phenol + \\(CHCl_3\\) + aqueous NaOH at \\(\\sim 340\\ \\mathrm{K}\\) (Reimer–Tiemann) — major product?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"orgo_on"}$k064c$::jsonb, $k064o$["**Salicylaldehyde** (2-hydroxybenzaldehyde)","Benzoic acid","Anisole","p-Hydroxybenzaldehyde only"]$k064o$::jsonb, 0, $k064e$Dichlorocarbene ortho-formylation of phenoxide.$k064e$),
  ('academic', 'chemistry', 1776, $k065c${"text":"Why do carboxylic acids often **not** show simple carbonyl addition reactions like some aldehydes/ketones (e.g. typical DNP test behavior)?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"orgo_on"}$k065c$::jsonb, $k065o$["Resonance with OH reduces electrophilicity of the carbonyl carbon.","The carbonyl is non-planar always.","Carboxylic acids lack a carbonyl group.","DNP only reacts with acids."]$k065o$::jsonb, 0, $k065e$Acyl carbon is less electrophilic due to \(RC(OH)=O\leftrightarrow RC(O^-)=OH^+\) type resonance.$k065e$),
  ('academic', 'chemistry', 1783, $k066c${"text":"\\(C_3H_9N\\) + benzenesulfonyl chloride → solid **insoluble in alkali**. Classification?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"orgo_on"}$k066c$::jsonb, $k066o$["**Secondary amine** (e.g. \\(N\\)-methylethanamine pattern)","Primary amine","Tertiary amine","Quaternary ammonium salt"]$k066o$::jsonb, 0, $k066e$Hinsberg: secondary sulfonamide has no acidic N–H on sulfonamide to deprotonate in base.$k066e$),
  ('academic', 'chemistry', 1789, $k067c${"text":"Esterification RCOOH + R'OH: which oxygen of the **water** formed comes from the acid?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"orgo_on"}$k067c$::jsonb, $k067o$["The acid’s hydroxyl is lost as water; the alcohol oxygen stays in the ester (classic mechanism).","Always from the alcohol OH.","Half from each randomly.","From the catalyst only."]$k067o$::jsonb, 0, $k067e$Nucleophilic acyl substitution pathway.$k067e$),
  ('academic', 'chemistry', 1795, $k068c${"text":"Benzamide + \\(Br_2\\) + conc. aqueous KOH — product?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"orgo_on"}$k068c$::jsonb, $k068o$["**Aniline** (Hofmann bromamide degradation)","Benzoic acid","Bromobenzene","Phenyl isocyanate only"]$k068o$::jsonb, 0, $k068e$Loses the carbonyl carbon as \(CO_2/\)carbonate; chain shortened by one to \(ArNH_2\).$k068e$),
  ('academic', 'chemistry', 1801, $k069c${"text":"Why is \\(Cl_3CCOOH\\) stronger than \\(CH_3COOH\\) but weaker than \\(CF_3COOH\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"orgo_on"}$k069c$::jsonb, $k069o$["Inductive order: F withdraws electron density more strongly than Cl, better stabilizing the carboxylate.","Chlorine is more electronegative than fluorine.","Size alone decides; no inductive effect.","All trihalomethyl acids have identical \\(pK_a\\)."]$k069o$::jsonb, 0, $k069e$\(-I\) effect scales with electronegativity.$k069e$),
  ('academic', 'chemistry', 1807, $k070c${"text":"Acetone + \\(CH_3MgBr\\), then \\(H_3O^+\\) — product IUPAC?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"orgo_on"}$k070c$::jsonb, $k070o$["**2-methylpropan-2-ol** (tert-butyl alcohol)","Propan-2-ol only","Butanal","2-methylbutan-2-ol"]$k070o$::jsonb, 0, $k070e$Grignard adds to ketone → tertiary alcohol after workup.$k070e$),
  ('academic', 'chemistry', 1814, $k071c${"text":"CFT: why do strong-field ligands like \\(CN^-\\) favor **low-spin** in many \\(d^4\\)–\\(d^7\\) octahedral complexes?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"coordination"}$k071c$::jsonb, $k071o$["Large \\(\\Delta_o\\) makes pairing in \\(t_{2g}\\) cheaper than promoting electrons to \\(e_g\\) when \\(\\Delta_o > P\\).","They always shrink the metal ion radius only.","They remove all \\(d\\) electrons.","Low spin only occurs in tetrahedral complexes."]$k071o$::jsonb, 0, $k071e$Crystal-field splitting exceeds electron pairing energy.$k071e$),
  ('academic', 'chemistry', 1820, $k072c${"text":"Spin-only magnetic moment of \\([Fe(CN)_6]^{3-}\\) (strong field, low spin \\(d^5\\))?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"coordination"}$k072c$::jsonb, $k072o$["\\(\\approx 1.73\\ \\mathrm{BM}\\)","\\(5.92\\ \\mathrm{BM}\\)","\\(0\\ \\mathrm{BM}\\)","\\(4.90\\ \\mathrm{BM}\\)"]$k072o$::jsonb, 0, $k072e$One unpaired electron: \(\mu = \sqrt{n(n+2)}\ \mathrm{BM}\).$k072e$),
  ('academic', 'chemistry', 1826, $k073c${"text":"Hall–Héroult: why add cryolite (\\(Na_3AlF_6\\)) to alumina?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"coordination"}$k073c$::jsonb, $k073o$["Lowers melting point and improves melt conductivity for practical electrolysis.","Removes iron impurities only.","Prevents aluminum from conducting.","Increases melting point above \\(2000^\\circ\\mathrm{C}\\)."]$k073o$::jsonb, 0, $k073e$Solvent flux for \(Al_2O_3\) dissolution at \(\sim 950^\circ\mathrm{C}\).$k073e$),
  ('academic', 'chemistry', 1832, $k074c${"text":"EAN of Co in \\([Co(NH_3)_6]^{3+}\\) (\\(Z_{\\mathrm{Co}} = 27\\)) using \\(Z - \\mathrm{OS} + 2 \\times \\mathrm{CN}\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"coordination"}$k074c$::jsonb, $k074o$["\\(36\\) (Kr-like count)","\\(33\\)","\\(30\\)","\\(27\\)"]$k074o$::jsonb, 0, $k074e$\(27 - 3 + 12 = 36\).$k074e$),
