  ('academic', 'chemistry', 1845, $k076c${"text":"IUPAC name of \\(K_3[Fe(C_2O_4)_3]\\)?","pack":"puc_chemistry_jee_neet_100","qtype":"numerical","block":"coordination"}$k076c$::jsonb, $k076o$["**Potassium trioxalatoferrate(III)**","Potassium iron(III) oxalate without charge balance","Iron(II) trioxalate","Potassium hexacyanoferrate(III)"]$k076o$::jsonb, 0, $k076e$Oxalate is bidentate; anionic complex uses -ate suffix; oxidation state +3.$k076e$),
  ('academic', 'chemistry', 1851, $k077c${"text":"Mond process: why is volatile \\(Ni(CO)_4\\) formation useful?","pack":"puc_chemistry_jee_neet_100","qtype":"conceptual","block":"coordination"}$k077c$::jsonb, $k077o$["Separates Ni as vapor from solid impurities, then thermal decomposition gives pure Ni and regenerates CO.","It increases Ni melting point.","It only removes sulfur.","CO is consumed irreversibly only."]$k077o$::jsonb, 0, $k077e$Volatility enables purification cycle.$k077e$),
